class APIKeyManager:
    """Manages API keys for application-level authentication."""

    def __init__(self):
        self._api_keys: Dict[str, Dict[str, Any]] = {}

    def generate_api_key(self, user_id: str, permissions: List[str]) -> str:
        """Generate a new API key with specific permissions."""
        allowed_permissions = {'read', 'write', 'search', 'admin', 'log_read', 'log_write'}
        validated_permissions = [p for p in permissions if p in allowed_permissions]

        if not validated_permissions:
            raise ValueError("No valid permissions specified")

        raw_key = secrets.token_urlsafe(48)
        key_hash = hashlib.sha256(raw_key.encode()).hexdigest()

        self._api_keys[key_hash] = {
            'user_id': user_id,
            'permissions': validated_permissions,
            'created_at': datetime.now(timezone.utc).isoformat(),
            'active': True,
        }

        return raw_key

    def validate_api_key(self, api_key: str, required_permission: str) -> bool:
        """Validate an API key and check permissions."""
        if not api_key or not isinstance(api_key, str):
            return False

        key_hash = hashlib.sha256(api_key.encode()).hexdigest()
        key_data = self._api_keys.get(key_hash)

        if not key_data or not key_data.get('active'):
            return False

        if required_permission not in key_data.get('permissions', []):
            logger.warning(
                "Permission denied for user %s: required %s",
                key_data.get('user_id', 'unknown'),
                required_permission
            )
            return False

        return True

    def revoke_api_key(self, api_key: str) -> bool:
        """Revoke an API key."""
        key_hash = hashlib.sha256(api_key.encode()).hexdigest()
        if key_hash in self._api_keys:
            self._api_keys[key_hash]['active'] = False
            return True
        return False


def require_permission(permission: str):
    """Decorator to enforce permission checks on methods."""
    def decorator(func):
        @wraps(func)
        def wrapper(self, *args, **kwargs):
            api_key = kwargs.get('api_key') or (args[0] if args else None)
            if not isinstance(api_key, str):
                raise PermissionError("API key is required")

            if not self.api_key_manager.validate_api_key(api_key, permission):
                raise PermissionError(f"Insufficient permissions: {permission} required")

            return func(self, *args, **kwargs)
        return wrapper
    return decorator


class ElasticsearchClient:
    """Secure Elasticsearch client with authentication and input validation."""

    def __init__(self):
        self.es = self._create_secure_connection()
        self.api_key_manager = APIKeyManager()
